  1→import { createContext, lazy, Suspense, useCallback, useContext, useEffect, useRef, useState } from 'react';
  2→import { SketchProvider, useSketch } from './app/SketchProvider';
  3→import { SketchEditorProvider, useSketchEditor } from './app/SketchEditorProvider';
  4→import SketchToolbar from './ui/SketchToolbar';
  5→import SketchSidebar from './ui/SketchSidebar';
  6→import SketchCanvas from './renderers/SketchCanvas';
  7→import SketchPropertiesPanel from './ui/SketchPropertiesPanel';
  8→import { saveSketchProject, loadSketchProject, listSketchProjects, deleteSketchProject } from './persistence/sketchStorage';
  9→import { exportSketchProjectFile, openSketchProjectFile, importSketchProjectFile, isFilePickerAbortError } from './persistence/sketchFileTransfer';
 10→import { useSketchAutosave } from './persistence/useSketchAutosave';
 11→import Modal from '@/ui/Modal';
 12→import TemplateDialog from './ui/TemplateDialog';
