 19→const SketchProjectContext = createContext(null);
 20→
 21→export function useSketchProject() {
 22→  const ctx = useContext(SketchProjectContext);
 23→  if (!ctx) throw new Error('useSketchProject must be used within SketchWorkspace');
 24→  return ctx;
 25→}
