 45→    case 'PAN': {
 46→      const vpKey = state.workspaceMode === 'sheet' ? 'sheetViewport' : 'modelViewport';
 47→      return {
 48→        ...state,
 49→        [vpKey]: {
 50→          ...state[vpKey],
 51→          panX: state[vpKey].panX + action.dx,
