 53→        },
 54→      };
 55→    }
 56→
 57→    case 'ZOOM': {
 58→      const { zoom, panX, panY } = action;
 59→      const vpKey = state.workspaceMode === 'sheet' ? 'sheetViewport' : 'modelViewport';
 60→      return {
 61→        ...state,
 62→        [vpKey]: { zoom, panX, panY },
 63→      };
 64→    }
 65→
 66→    case 'SET_WORKSPACE_MODE':
 67→      return {
 68→        ...state,
 69→        workspaceMode: action.workspaceMode,
 70→        selectedId: null,
 71→        selectedType: null,
 72→      };
 73→
 74→    case 'SET_ACTIVE_SHEET':
 75→      return {
 76→        ...state,
 77→        activeSheetId: action.sheetId,
 78→        selectedId: null,
 79→        selectedType: null,
 80→      };
 81→
 82→    case 'SET_VIEW':
 83→      return {
 84→        ...state,
 85→        activeView: action.view,
 86→      };
 87→
 88→    case 'SET_ACTIVE_ASSEMBLY':
 89→      return {
 90→        ...state,
 91→        activeAssemblyId: action.assemblyId,
 92→      };
