  1→import { createContext, useContext, useReducer, useCallback } from 'react';
  2→import { createSketchProject } from '../domain/sketchModels';
  3→import { sanitizePartDimensions, sanitizePartPosition } from '../domain/validation';
  4→import { resolveConstraints } from '../domain/constraintResolver';
  5→import { updateBoundDimensionEndpoints } from '../domain/dimensionBinding';
  6→import { generateId } from '@/domain/ids';
  7→import { generateObjectFromTemplate } from '../domain/objectGenerator';
  8→import { normalizeSketchObjects } from '../domain/objectModels';
  9→
 10→const SketchContext = createContext(null);
 11→const HISTORY_LIMIT = 80;
 12→
 13→function snapshotSketch(sketchProject) {
 14→  return JSON.stringify(sketchProject);
 15→}
 16→
 17→function applyUpdate(state, nextProject, recordHistory = true) {
 18→  const normalizedProject = normalizeSketchObjects(nextProject);
 19→  const nextSnapshot = snapshotSketch(normalizedProject);
 20→  const history = recordHistory
 21→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
 22→    : state.history;
 23→
 24→  return {
 25→    ...state,
 26→    history,
 27→    future: recordHistory ? [] : state.future,
 28→    project: normalizedProject,
 29→    isDirty: nextSnapshot !== state.savedSnapshot,
 30→  };
 31→}
 32→
 33→function mergePart(existing, updates) {
 34→  const merged = { ...existing, ...updates };
 35→  if (updates.position) {
 36→    merged.position = { ...existing.position, ...updates.position };
 37→  }
 38→  if (updates.rotation) {
 39→    merged.rotation = { ...existing.rotation, ...updates.rotation };
 40→  }
 41→  return merged;
 42→}
 43→
 44→function sanitizePart(part) {
 45→  if (part.type === 'dimension') return part;
 46→  return sanitizePartPosition(sanitizePartDimensions(part));
 47→}
 48→
 49→function applyConstraints(project) {
 50→  const constraints = project.constraints || [];
 51→  if (constraints.length === 0) return project;
 52→
 53→  const resolved = resolveConstraints(constraints, project.parts);
 54→  if (resolved.size === 0) return project;
 55→
 56→  return {
 57→    ...project,
 58→    parts: project.parts.map((part) => {
 59→      const newPos = resolved.get(part.id);
 60→      return newPos ? { ...part, position: newPos } : part;
 61→    }),
 62→  };
 63→}
 64→
 65→function updateBoundDimensions(project, updatedPartId) {
 66→  const updatedPart = project.parts.find((part) => part.id === updatedPartId);
 67→  if (!updatedPart) return project;
 68→
 69→  let changed = false;
 70→  const newParts = project.parts.map((part) => {
 71→    if (part.type === 'dimension' && part.boundPartId === updatedPartId) {
 72→      changed = true;
 73→      return updateBoundDimensionEndpoints(part, updatedPart);
 74→    }
 75→    return part;
 76→  });
 77→
 78→  return changed ? { ...project, parts: newParts } : project;
 79→}
 80→
 81→function clonePart(part, idMap) {
 82→  const newId = generateId('part');
 83→  idMap.set(part.id, newId);
 84→  return {
 85→    ...part,
 86→    id: newId,
 87→    name: `${part.name} (copy)`,
 88→    objectId: part.objectId || null,
 89→    source: 'manual',
 90→    locked: false,
 91→    position: {
 92→      ...part.position,
 93→      x: part.position.x + 50,
 94→      y: part.position.y + 50,
 95→    },
 96→  };
 97→}
 98→
 99→function getManagedObject(project, objectId) {
100→  if (!objectId) return null;
101→  return (project.objects || []).find((object) => object.id === objectId) || null;
102→}
103→
104→function getManagedObjectForPart(project, partId) {
105→  const part = project.parts.find((entry) => entry.id === partId);
106→  const object = part?.objectId ? getManagedObject(project, part.objectId) : null;
107→  return object?.editingPolicy === 'parametric' ? object : null;
108→}
109→
110→function getManagedObjectForAssembly(project, assemblyId) {
111→  const assembly = project.assemblies.find((entry) => entry.id === assemblyId);
112→  const object = assembly?.objectId ? getManagedObject(project, assembly.objectId) : null;
113→  return object?.editingPolicy === 'parametric' ? object : null;
114→}
115→
116→function removePartsAndAssemblies(project, { partIds, assemblyIds }) {
117→  const idsToRemove = new Set(partIds);
118→  const assemblyIdSet = new Set(assemblyIds);
119→
120→  const childIds = new Set(
121→    project.parts.filter((part) => idsToRemove.has(part.parentId)).map((part) => part.id)
122→  );
123→  for (const childId of childIds) idsToRemove.add(childId);
124→
125→  const constraints = (project.constraints || []).filter(
126→    (constraint) => !idsToRemove.has(constraint.sourcePartId) && !idsToRemove.has(constraint.targetPartId)
127→  );
128→
129→  return {
130→    ...project,
131→    parts: project.parts
132→      .filter((part) => !idsToRemove.has(part.id))
133→      .map((part) => {
134→        if (part.type === 'dimension' && part.boundPartId && idsToRemove.has(part.boundPartId)) {
135→          return { ...part, boundPartId: null, boundProperty: null, boundAxis: null };
136→        }
137→        return part;
138→      }),
139→    assemblies: project.assemblies.filter((assembly) => !assemblyIdSet.has(assembly.id)),
140→    constraints,
141→  };
142→}
143→
144→function removeObjectArtifacts(project, objectId) {
145→  const partIds = project.parts
146→    .filter((part) => part.objectId === objectId)
147→    .map((part) => part.id);
148→  const assemblyIds = project.assemblies
149→    .filter((assembly) => assembly.objectId === objectId)
150→    .map((assembly) => assembly.id);
151→
152→  return removePartsAndAssemblies(project, { partIds, assemblyIds });
153→}
154→
155→function retargetManagedViewports(sheets, objectId, oldAssemblyIds = []) {
156→  const oldAssemblyIdSet = new Set(oldAssemblyIds);
157→
158→  return (sheets || []).map((sheet) => ({
159→    ...sheet,
160→    viewports: (sheet.viewports || []).map((viewport) => {
161→      if (viewport.sourceRefId !== objectId && !oldAssemblyIdSet.has(viewport.sourceRefId)) {
162→        return viewport;
163→      }
164→
165→      if (viewport.sourceView === 'sketch_assembly_top') {
166→        return { ...viewport, sourceView: 'sketch_object_top', sourceRefId: objectId };
167→      }
168→      if (viewport.sourceView === 'sketch_assembly_front') {
169→        return { ...viewport, sourceView: 'sketch_object_front', sourceRefId: objectId };
170→      }
171→      if (viewport.sourceView === 'sketch_assembly_side') {
172→        return { ...viewport, sourceView: 'sketch_object_side', sourceRefId: objectId };
173→      }
174→      if (viewport.sourceView === 'sketch_part_list') {
175→        return { ...viewport, sourceRefId: objectId, sourceObjectId: objectId };
176→      }
177→
178→      return viewport;
179→    }),
180→  }));
181→}
182→
183→function detachManagedObject(project, objectId) {
184→  return {
185→    ...project,
186→    objects: (project.objects || []).map((object) => (
187→      object.id === objectId
188→        ? {
189→            ...object,
190→            source: 'custom',
191→            editingPolicy: 'manual',
192→            templateType: null,
193→            templateParams: null,
194→            summary: object.summary || 'Detached custom object',
195→            updatedAt: new Date().toISOString(),
196→          }
197→        : object
198→    )),
199→    assemblies: project.assemblies.map((assembly) => (
200→      assembly.objectId === objectId
201→        ? {
202→            ...assembly,
203→            source: 'manual',
204→            role: assembly.role || null,
205→          }
206→        : assembly
207→    )),
208→    parts: project.parts.map((part) => (
209→      part.objectId === objectId
210→        ? {
211→          ...part,
212→            source: 'manual',
213→            locked: false,
214→          }
215→        : part
216→    )),
217→  };
218→}
219→
220→function addGeneratedObject(project, generated) {
221→  return {
222→    ...project,
223→    objects: [...(project.objects || []), generated.object],
224→    assemblies: [...project.assemblies, ...generated.assemblies],
225→    parts: [...project.parts, ...generated.parts.map(sanitizePart)],
226→  };
227→}
228→
229→function rebuildManagedObject(project, object, params) {
230→  const oldAssemblyIds = project.assemblies
231→    .filter((assembly) => assembly.objectId === object.id)
232→    .map((assembly) => assembly.id);
233→
234→  const strippedProject = removeObjectArtifacts(project, object.id);
235→  const generated = generateObjectFromTemplate(object.templateType, params, {
236→    objectId: object.id,
237→    name: object.name,
238→    origin: object.origin,
239→  });
240→
241→  const nextProject = addGeneratedObject({
242→    ...strippedProject,
243→    objects: (strippedProject.objects || []).filter((entry) => entry.id !== object.id),
244→    sheets: retargetManagedViewports(strippedProject.sheets, object.id, oldAssemblyIds),
245→  }, generated);
246→
247→  return nextProject;
248→}
