707→        updatedAt: new Date().toISOString(),
708→        ...action.meta,
709→      });
710→
711→    case 'SKETCH_SHEET_ADD':
712→      return applyUpdate(state, {
713→        ...state.project,
714→        updatedAt: new Date().toISOString(),
715→        sheets: [...(state.project.sheets || []), action.sheet],
716→      });
717→
718→    case 'SKETCH_SHEET_UPDATE':
719→      return applyUpdate(state, {
720→        ...state.project,
721→        updatedAt: new Date().toISOString(),
722→        sheets: (state.project.sheets || []).map((sheet) => (
723→          sheet.id === action.sheet.id ? { ...sheet, ...action.sheet } : sheet
724→        )),
725→      });
726→
727→    case 'SKETCH_SHEET_DELETE':
728→      return applyUpdate(state, {
729→        ...state.project,
730→        updatedAt: new Date().toISOString(),
731→        sheets: (state.project.sheets || []).filter((sheet) => sheet.id !== action.sheetId),
732→      });
733→
734→    case 'SKETCH_SHEET_VIEWPORT_ADD': {
735→      const targetSheet = (state.project.sheets || []).find((sheet) => sheet.id === action.sheetId);
736→      if (!targetSheet) return state;
737→      return applyUpdate(state, {
738→        ...state.project,
739→        updatedAt: new Date().toISOString(),
740→        sheets: state.project.sheets.map((sheet) => (
741→          sheet.id === action.sheetId
742→            ? { ...sheet, viewports: [...(sheet.viewports || []), action.viewport] }
743→            : sheet
744→        )),
745→      });
746→    }
747→
748→    case 'SKETCH_SHEET_VIEWPORT_UPDATE':
749→      return applyUpdate(state, {
750→        ...state.project,
751→        updatedAt: new Date().toISOString(),
752→        sheets: (state.project.sheets || []).map((sheet) => (
753→          sheet.id === action.sheetId
754→            ? {
755→                ...sheet,
756→                viewports: (sheet.viewports || []).map((viewport) => (
757→                  viewport.id === action.viewport.id ? { ...viewport, ...action.viewport } : viewport
758→                )),
759→              }
