 3→export function sketchDeserialize(json) {
 4→  if (!json || json.schemaType !== 'sketch') {
 5→    throw new Error('Invalid sketch project data: missing or wrong schemaType');
 6→  }
 7→
 8→  const project = json.data;
 9→  if (!project || !project.id || !project.name) {
10→    throw new Error('Invalid sketch project data: missing required fields');
11→  }
12→
13→  // Ensure arrays exist
14→  project.parts = project.parts || [];
15→  project.assemblies = project.assemblies || [];
16→  project.constraints = project.constraints || [];
17→  project.annotations = project.annotations || [];
18→  project.sheets = project.sheets || [];
19→  project.objects = project.objects || [];
20→
21→  return {
22→    project: normalizeSketchObjects(project),
23→    savedAt: json.savedAt,
24→  };
